sp_widget.client_script:
api.controller = function($scope, $timeout) {
  var c = this;
	c.showModal = false;
	c.migrationResult = {};
  c.batchSize = 100;
  c.showToast = false;
  c.migrating = false;
	c.progress = 0;
	c.current = 0;
	c.table_count = 0;
	c.total = 0;
  c.check = sessionStorage.getItem('currentId');
	c.logs = [];
	c.isCompleted = false;
	c.conn_name = '';



  /* =========================
     NOTIFICATION SYSTEM
  ========================= */

  c.createNotification = function(notification) {
    $scope.server.get({
      action: "createNotification",
      payload: notification
    }).then(function() {
      $scope.$emit("notification.refresh");
    });
  };

	//Migration Modal
	c.openMigrationModal = function() {

  if (c.getTotalRecords() === 0)
    return;

  c.showModal = true;      // 🔥 OPEN MODAL FIRST
  c.migrationResult = {};
  c.progress = 0;

  c.startMigration();      // 🔥 then start migration
	};

	//Close Modal
	c.closeModal = function() {
  c.showModal = false;
	};

  /* =========================
     CART DATA
  ========================= */

  c.cart = [];

  /* =========================
     LOAD CART FROM SESSION
  ========================= */

  c.loadCart = function() {

  var raw = JSON.parse(
    sessionStorage.getItem("migration_cart") || "[]"
  );
	c.selected_recs = raw.length;

  /* =========================
     DETECT NEWLY ADDED RECORDS
  ========================= */

  if (c.previousCartLength !== undefined &&
      raw.length > c.previousCartLength) {

    var addedCount =
      raw.length - c.previousCartLength;

    c.createNotification({
      type: "queue_record_added",
      title: "Records added to migration queue",
      message: addedCount + " record(s) added to queue.",
      priority: "info"
    });

  }

  c.previousCartLength = raw.length;


  /* =========================
     QUEUE LIMIT WARNING
  ========================= */

  if (raw.length >= 10000) {

    c.createNotification({
      type: "queue_limit_reached",
      title: "Migration queue limit reached",
      message: "Maximum queue size reached (10,000 records).",
      priority: "warning"
    });

  }


  /* =========================
     GROUP RECORDS BY TABLE
  ========================= */

  var grouped = {};

  raw.forEach(function(item) {

    if (!grouped[item.table]) {

      grouped[item.table] = {

        name: item.table,
        label: item.label,
        records: []

      };

    }

    grouped[item.table].records.push({

      number: item.number || "",
      short_description: item.short_description || "",
      size: item.size || 0,
      table: item.table || "",
      sys_id: item.sys_id || ""

    });

  });


  /* =========================
     UPDATE CART STRUCTURE
  ========================= */

  c.cart = Object.keys(grouped).map(function(key) {

    return grouped[key];

  });


  /* =========================
     🔥 NOTIFY HEADER WIDGET
     (REAL-TIME CART SYNC)
  ========================= */

  window.dispatchEvent(
    new Event("cartUpdated")
  );

  $scope.$emit("cartUpdated");

};

  /* =========================
     START MIGRATION
  ========================= */

/*c.startMigration = function() {

  if (c.getTotalRecords() === 0)
    return;

  c.migrating = true;
  c.progress = 0;
  c.showToast = false;

  var cartRaw = JSON.parse(sessionStorage.getItem('migration_cart') || '[]');

  // 🔥 estimate total records
  c.total = 0;
  cartRaw.forEach(function(g){
    c.total += (g.records || []).length;
  });

  var progressInterval;

  // 🔥 FAKE PROGRESS (smooth UI)
  progressInterval = setInterval(function() {

    if (c.progress < 90) {
      c.progress += Math.floor(Math.random() * 5) + 1;
    }

    $scope.$applyAsync();

  }, 500);

  $scope.server.get({
    action: "migrateRecords",
    active_conn: sessionStorage.getItem('currentId'),
    cart_length: c.total,
    records: c.cart
  }).then(function(response) {

    clearInterval(progressInterval);

    c.progress = 100;
    c.migrating = false;

    if (response.data && response.data.success) {
      c.clearCart();
      c.toastMessage = "Migration completed";
    } else {
      c.toastMessage = "Migration failed";
      console.error(response.data.error);
    }

    c.showToast = true;

    $timeout(function() {
      c.showToast = false;
    }, 4000);

  }, function(err) {

    clearInterval(progressInterval);

    c.migrating = false;
    c.progress = 0;

    c.toastMessage = "Migration failed";
    console.error(err);

    c.showToast = true;

    $timeout(function() {
      c.showToast = false;
    }, 4000);
  });
};*/

	c.startMigration = function() {

  if (c.getTotalRecords() === 0)
    return;
	c.logs.push("Starting migration...");

  /* OPEN MODAL */
  c.showModal = true;
  c.migrating = true;
  c.progress = 0;
  c.migrationResult = {};

  var cartRaw = JSON.parse(sessionStorage.getItem('migration_cart') || '[]');

  c.total = 0;
  cartRaw.forEach(function(g){
    c.total += (g.records || []).length;
  });

  var progressInterval;

  /* 🔥 FAKE PROGRESS */
  progressInterval = setInterval(function() {

    if (c.progress < 90) {
      c.progress += Math.floor(Math.random() * 5) + 1;
    }

    // prevent overflow
    if (c.progress > 90) {
      c.progress = 90;
    }

    $scope.$applyAsync();

  }, 500);

  /* SERVER CALL */
  $scope.server.get({
    action: "migrateRecords",
    active_conn: sessionStorage.getItem('currentId'),
    cart_length: c.total,
    records: c.cart
  }).then(function(response) {
			clearInterval(progressInterval);

			/* COMPLETE */
			c.progress = 100;
			c.migrating = false;
    if (response.data && response.data.success) {
			c.logs.push("Migration completed");
			c.logs.push("Migration started at " + response.data.sTime);
			c.logs.push("Migration completed at " + response.data.eTime);
			c.isCompleted = true;
			c.conn_name = response.data.conn_name;
			c.inserted = response.data.inserted;
			c.updated = response.data.updated;
			c.total = response.data.total;
			c.url = response.data.url;
      c.migrationResult = response.data.result;
      c.clearCart();
    } else {
			c.logs.push("Migration failed");
      c.migrationResult = {
        error: true,
        message: "Migration failed"
      };
    }

  }, function(err) {

    clearInterval(progressInterval);

    c.migrating = false;
    c.progress = 0;

    c.migrationResult = {
      error: true,
      message: "Migration failed"
    };

    console.error(err);
  });
};



  /* =========================
     REMOVE RECORD
  ========================= */

  c.removeRecord = function(tableIndex, recordIndex) {
    var rec = c.cart[tableIndex].records[recordIndex];
    var recordLabel = rec.number || rec.sys_id || "Record";

    c.createNotification({
      type: "queue_record_removed",
      title: "Record removed from migration queue",
      message: recordLabel + " removed from queue.",
      priority: "info"
    });

    c.cart[tableIndex].records.splice(recordIndex, 1);

    if (c.cart[tableIndex].records.length === 0) {
      c.cart.splice(tableIndex, 1);
    }

    var raw = JSON.parse(sessionStorage.getItem("migration_cart") || "[]");

    raw = raw.filter(function(r) {
      return r.sys_id !== rec.sys_id;
    });

    sessionStorage.setItem("migration_cart", JSON.stringify(raw));
		sessionStorage.setItem('cart_items', JSON.stringify((raw)))

window.dispatchEvent(new Event("cartUpdated"));
$scope.$emit("cartUpdated");
  };

  /* =========================
     CLEAR CART
  ========================= */

  c.clearCart = function() {
    c.cart = [];
   sessionStorage.removeItem("migration_cart");

window.dispatchEvent(new Event("cartUpdated"));
$scope.$emit("cartUpdated");

    c.createNotification({
      type: "queue_cleared",
      title: "Migration queue cleared",
      message: "All records removed from migration queue.",
      priority: "warning"
    });
  };

  /* =========================
     PREVIEW MODAL
  ========================= */

  c.previewOpen = false;
  c.previewData = {};

  c.openPreview = function(record) {
    c.previewData = record;
    c.previewOpen = true;
  };

  c.closePreview = function() {
    c.previewOpen = false;
  };

  /* =========================
     TOTAL RECORDS
  ========================= */

  c.getTotalRecords = function() {
    var total = 0;
    c.cart.forEach(function(table) {
      total += table.records.length;
    });
    return total;
  };

  /* =========================
     TOTAL TABLES
  ========================= */

  c.getTotalTables = function() {
    return c.cart.length;
  };

  /* =========================
     TOTAL SIZE
  ========================= */

  c.getTotalSize = function() {
    var total = 0;
    c.cart.forEach(function(table) {
      table.records.forEach(function(rec) {
        total += parseFloat(rec.size || 0);
      });
    });
    return total.toFixed(1);
  };

  /* =========================
     BATCH COUNT
  ========================= */

  c.getBatchCount = function() {
    var total = c.getTotalRecords();
    if (total === 0)
      return 0;
    return Math.ceil(total / c.batchSize);
  };

  /* =========================
     AUTO LOAD CART
  ========================= */

  c.loadCart();

  /* =========================
     AUTO UPDATE IF STORAGE CHANGES
  ========================= */

  window.addEventListener("storage", function() {
    $scope.$apply(function() {
      c.loadCart();
    });
  });
};

sp_widget.css:
/* ===== Main Container ===== */
.migration-cart {
  display: flex;
  max-height: calc(100vh - 64px);
position:relative;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(13, 124, 143, 0.05) 50%,
    rgba(23, 162, 184, 0.10) 100%
  );
}

.con {
  display: flex;
  min-height: 100vh;
}

.sidebar {
    flex-basis: 260px;
  flex-shrink:0;
  height:100%;
}
.cart-svg-icon {
  color: #94a3b8;
}
.main {
  position:relative;
  display: flex;
  flex-direction: column;
  height:100%;
  gap:30px;
  margin: 0 auto;
  overflow-y:auto;
  height:calc(100vh - 64px);
  width: 100%;
  padding: 30px 15%;
}

/* ===== Header ===== */
.cart-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 25px;
}

.cart-header h2 {
  font-weight: 700;
  margin-bottom: 5px;
}

.subtitle {
  color: #64748b;
  font-size: 14px;
}

/* ===== Back Button ===== */
.back-link {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  color: #6b7280;
  text-decoration: none;
  font-size: 14px;
  margin-bottom: 10px;
  transition: all 0.2s ease;
}

.back-link:hover {
  color: #1F8C95 ;
}

/* ===== Buttons ===== */
.btn-danger {
  background: #fff0f0;
  border: 1px solid #ffc9c9;
  color: #dc2626;
  border-radius: 8px;
  padding: 6px 14px;

  transition: transform 0.15s ease;   /* ONLY animate scale */
  box-shadow: none !important;        /* 🔥 force remove */
}

/* Hover → only scale */
.btn-danger:hover {
  transform: scale(1.08);
  background: #fff0f0;
  box-shadow: none !important;
}

/* Remove click/focus/active effects completely */
.btn-danger:focus,
.btn-danger:active,
.btn-danger:focus:active {
  box-shadow: none !important;
  outline: none !important;
  background: #fff0f0 !important;
  color: #dc2626 !important;
  transform: scale(1.05); /* optional slight press */
}

/* Remove Bootstrap default transition delay */
.btn {
  transition: none !important;
}

/* Remove click/active red effect */
.btn-danger:active,
.btn-danger:focus {
  background: #fff0f0 !important;
  color: #dc2626 !important;
  box-shadow: none !important;
  outline: none;
}
.btn-primary {
   background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
  border: none;
  padding: 10px 20px;
  border-radius: 8px;
  color: white;
}


/* ===== Stats ===== */
.stats-container {
  display: flex;
  gap: 20px;
  margin-bottom: 25px;
}

.stat-box {
  flex: 1;
  background: white;
  padding: 22px;
  border-radius: 14px;
  text-align: center;
  box-shadow: 0 8px 20px rgba(0,0,0,0.05);
}

.stat-box h3 {
  font-size: 26px;
  font-weight: 700;
}

/* ===== Cart Section ===== */
.cart-section {
  background: white;
  padding: 25px;
  border-radius: 14px;
  box-shadow: 0 8px 25px rgba(0,0,0,0.04);
  margin-bottom: 25px;
}


.cart-section.empty-mode {
  display: flex;
  justify-content: center;
  align-items: center;
  width: 900px;
  min-height: 420px;
  margin: 0 auto;
  border-radius: 18px;
}
.cart-section.has-records {
  display: block;
}
.cart-section h4 {
  margin-bottom: 20px;
  font-weight: 600;
}


.empty-cart-screen {
  width: 100%;
  max-width: 650px;
  text-align: center;

  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
}

.empty-icon {
  width: 90px;
  height: 90px;
  border-radius: 50%;
  background: #f1f5f9;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 25px;
  font-size: 34px;
  color: #94a3b8;
}

.empty-title {
  font-size: 34px;
  font-weight: 700;
  color: #0f172a;
  margin-bottom: 12px;
}

.empty-subtitle {
  font-size: 17px;
  color: #475569;
  line-height: 1.7;
  margin-bottom: 30px;
   max-width: 600px;
}
.browse-btn {
  background: #1F8C95 ;
  color: white;
  padding: 14px 30px;
  border-radius: 10px;
  text-decoration: none;
  font-weight: 600;
}
.browse-btn:hover{
   background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}

/* smooth transition */
.browse-btn i {
  transition: transform 0.25s ease;
  display: inline-block;
}

/* move icon on hover */
.browse-btn:hover i {
  transform: translateX(4px);
}
/* ===== Table Card ===== */
.table-card {
  border-radius: 12px;
  margin-bottom: 20px;
  background: #f9fafc;
  border: 1px solid #e2e8f0;
}

.table-header {
  display: flex;
  justify-content: space-between;
  padding: 18px 22px;
  background: #f1f5f9;
}

.badge-primary {
  background: #1F8C95 ;
  padding: 8px 18px;
  border-radius: 999px;
  color: white;

  display: inline-flex;
  align-items: center;
  justify-content: center;

  min-height: 40px;
  line-height: 1;
}


/* ===== Record ===== */
.record-item {
  display: flex;
  justify-content: space-between;
  padding: 18px;
  border-top: 1px solid #e5e7eb;
}

.record-number {
  color: #1F8C95 ;
}

.size-badge {
  background: #eef2ff;
  padding: 3px 10px;
  border-radius: 8px;
}

.table-header small {
  font-weight: 700;
  font-size: 14px;
  color: #334155;
}


.table-start-btn svg {
  margin-right: 8px;
  display: inline-block;
  vertical-align: middle;
}





/* ===== Batch / Ready ===== */

.ready-section {
  background: linear-gradient(135deg, #dbeafe, #eff6ff);
  padding: 25px;
  border-radius: 14px;
  margin: 0 0 20px 0;
   display: flex;
  justify-content: space-between;
  align-items: center;
}


.table-header {

  display: flex;

  align-items: center;

  justify-content: space-between;

  padding: 18px 22px;

  background: #f1f5f9;

  text-transform: uppercase;

}

/* Force EVERYTHING inside to stay in one line */

.table-header,

.table-header * {

  white-space: nowrap !important;

}

/* Prevent flex wrapping completely */

.table-header {

  flex-wrap: nowrap;

}

/* If text is too long → show ... instead of breaking */

.table-header .left {

  overflow: hidden;

  text-overflow: ellipsis;

}





/* ===== Toast ===== */
.migration-toast {
  position: fixed;
  bottom: 30px;
  right: 30px;
  background: #f1f5f9;
  border-radius: 12px;
  padding: 16px 20px;
}

/* ===== Loader ===== */
.migration-loader {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.5);
  display:flex;
  justify-content:center;
  align-items:center;
  flex-direction:column;
}

.spinner {
  width:50px;
  height:50px;
  border:5px solid #ccc;
  border-top:5px solid #4CAF50;
  border-radius:50%;
  animation: spin 1s linear infinite;
}

@keyframes spin {
  100% {
    transform: rotate(360deg);
  }
}
/* ======Migration Modal======*/
.migration-modal-backdrop {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0,0,0,0.5);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 9999;
}

.migration-modal {
  width: 500px;
  background: #fff;
  border-radius: 8px;
  overflow: hidden;
}

.modal-header {
  padding: 15px;
  border-bottom: 1px solid #ddd;
}

.modal-body {
  padding: 15px;
}

.modal-footer {
  padding: 10px;
  text-align: right;
  border-top: 1px solid #ddd;
}

.alert-success {
  background: #e6f4ea;
  color: #2e7d32;
  padding: 10px;
