  background: transparent;
  border: 1px solid #1F8C95;
  color: #1F8C95;
  padding: 8px 18px;
  border-radius: 999px;
  font-size: 13px;
  font-weight: 700;
  min-height: 40px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition: all 0.3s ease;
}


.table-start-btn:hover {
  background: linear-gradient(to right, #128a9a, #0a5f6d);
  color: white;
  border-color: transparent;
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
}



.actions {
  display: flex;
  align-items: center;
  gap: 12px;
}
.action-icon {
  cursor: pointer;
}

sp_widget.script:
(function(){

	data.side = $sp.getWidget('dmm_sidebar');
	//duration fields
	var duration = 0;
	var result = '', sTime = 0, eTime = 0;

	/* =========================
	   CREATE NOTIFICATION HANDLER
	========================= */

	if (input && input.action == "createNotification") {

		var notif = new GlideRecord("x_sysus_data_mig_0_notifications");

		notif.initialize();

		notif.setValue("title", input.payload.title);
		notif.setValue("message", input.payload.message);
		notif.setValue("type", input.payload.type);
		notif.setValue("priority", input.payload.priority);
		notif.setValue("user", gs.getUserID());
		notif.setValue("read", false);

		notif.insert();

		data.notificationCreated = true;

		return;
	}


	/* =========================
	   MIGRATION EXECUTION
	========================= */

	if (input && input.action == "migrateRecords") {

		var username, password, sourceurl;


		/* Migration Started Notification */

		var startNotif = new GlideRecord("x_sysus_data_mig_0_notifications");

		startNotif.initialize();

		startNotif.title = "Migration started";
		startNotif.message = "Migration process has started.";
		startNotif.type = "migration_started";
		startNotif.priority = "info";
		startNotif.user = gs.getUserID();
		startNotif.insert();


		var gr = new GlideRecord('x_sysus_data_mig_0_connection');

		gr.addQuery('sys_id', input.active_conn);
		gr.query();

		if (gr.next()) {

			username = gr.getValue('username');
			password = gr.getValue('password');
			sourceurl = gr.getValue('url');
			data.conn_name = gr.getValue('name');
		}


		var cart = input.records || [];

		var recordsToMigrate = {};


		/* Prepare table → sys_id mapping */

		cart.forEach(function(tableGroup){

			var table = tableGroup.name;

			if (!recordsToMigrate[table])
				recordsToMigrate[table] = [];

			tableGroup.records.forEach(function(rec){
				if (rec.sys_id)
					recordsToMigrate[table].push(
						String(rec.sys_id).trim()
					);

			});

		});


		/* Run migration engine */

		try {
			var engine = new global.UnifiedMigrationEngine();

			result = engine.batchMigration(

				sourceurl,
				username,
				password,
				recordsToMigrate

			);


			data.success = true;
			data.result  = result;

			/* Save migration result */

		var obj = {};

		var mig = new GlideRecord('x_sysus_data_mig_0_migration_details');
		mig.initialize();

		var inserted = engine.stats.inserted || 0;
		var updated  = engine.stats.updated  || 0;
		var failed   = engine.stats.failed   || 0;

		/* Calculate total fetched correctly */
		var total = 0;

		cart.forEach(function(tableGroup){
				total += (tableGroup.records || []).length;
		});

		/* Safe success rate */
		var successRate = 0;

		if (total > 0) {
				successRate = ((inserted + updated) / total) * 100;
		}

		/* Optional rounding */
		successRate = Math.round(successRate * 100) / 100;

		mig.setValue('instance_url', sourceurl);
		mig.setValue('records_fetched', total);
		mig.setValue('records_inserted', inserted);
		mig.setValue('records_updated', updated);
		mig.setValue('records_failed', failed);
		mig.setValue('success_rate', successRate);
		mig.setValue('duration', engine.durationText);
		//console.log(engine.startTime + engine.endTime);
		sTime = engine.startTime;
		eTime = engine.endTime;
		data.inserted = inserted;
		data.updated = updated;
		data.total = total;
		data.url = sourceurl;
		data.sTime = sTime.toString();
		data.eTime = eTime.toString();

		Object.keys(recordsToMigrate).forEach(function(key){
				obj[key] = "true";
		});

		mig.setValue('table', JSON.stringify(obj));

		/* (You forgot this ❗) */
		mig.insert();



			/* =========================
			   MIGRATION RESULT NOTIFICATION
			========================= */

			var resultNotif = new GlideRecord("x_sysus_data_mig_0_notifications");

			resultNotif.initialize();


			if (engine.stats.failed == 0) {

				resultNotif.title = "Migration completed successfully";

				resultNotif.message =
					(engine.stats.inserted + engine.stats.updated) +
					" records migrated successfully.";

				resultNotif.type = "migration_success";

				resultNotif.priority = "success";

			}

			else if (
				engine.stats.failed > 0 &&
				(engine.stats.inserted + engine.stats.updated) > 0
			) {

				resultNotif.title =engine.stats.failed +
					" records failed during migration.";

				resultNotif.message =
					engine.stats.failed +
					" records failed during migration.";

				resultNotif.type = "migration_warning";

				resultNotif.priority = "warning";

			}

			else {

				resultNotif.title = "Migration failed";

				resultNotif.message =
					"Migration failed. No records migrated.";

				resultNotif.type = "migration_failed";

				resultNotif.priority = "critical";

			}


			resultNotif.user = gs.getUserID();

			resultNotif.insert();

		}

		catch (e) {

			gs.error("Migration failed");
			gs.error(e);

			data.success = false;
			data.error   = e.toString();


			var failNotif = new GlideRecord("x_sysus_data_mig_0_notifications");

			failNotif.initialize();

			failNotif.title = "Migration failed";

			failNotif.message = e.toString();

			failNotif.type = "migration_failed";

			failNotif.priority = "critical";

			failNotif.user = gs.getUserID();

			failNotif.insert();

		}

	}

	//ProgressBar Calculation
	if (input && input.action == "getProgress") {

    var eng = new global.UnifiedMigrationEngine();

    var progress = eng.getProgress();

    data.progress = progress;
}

})();
